     , (@parent_id,  1,  10 /* Tell */, 1, 1, NULL, 'I''ve seen a number of pearls in my days... You know we exchange Niffis Pearls for writs correct? ... Anyway, I have seen a number of pearls before, but this is obviously not from any niffis I''ve seen.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
     , (@parent_id,  2,  10 /* Tell */, 1, 1, NULL, 'Look at how dark this pearl is, it seems to eat the very light around it. This is a truly rare find, some ancient Empyrean decoration no doubt, but I can''t imagine it would be very different from the niffis pearls we know of.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
