     , (@parent_id,  9,  10 /* Tell */, 0, 1, NULL, 'You are lucky I have learned about their strange methods of communication, otherwise I don''t think there''d be an Isparian alive who could translate this.', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL)
